// 游戏配置常量
const CONFIG = {
    GRID_SIZE: 20,
    CANVAS_WIDTH: 600,
    CANVAS_HEIGHT: 600,
    INITIAL_SPEED: 150,
    SPEED_DECREMENT: 5,
    MIN_SPEED: 50,
    COLORS: {
        SNAKE_HEAD: '#4CAF50',
        SNAKE_BODY: '#8BC34A',
        FOOD: '#FF5722',
        GRID: '#e0e0e0',
        BACKGROUND: '#f0f0f0'
    }
