    drawFood() {
        const pos = this.food.getPosition();
        const centerX = pos.x * CONFIG.GRID_SIZE + CONFIG.GRID_SIZE / 2;
        const centerY = pos.y * CONFIG.GRID_SIZE + CONFIG.GRID_SIZE / 2;
        const radius = CONFIG.GRID_SIZE / 2 - 2;

        this.ctx.fillStyle = CONFIG.COLORS.FOOD;
        this.ctx.beginPath();
        this.ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
        this.ctx.fill();

        // 添加一个小亮点
        this.ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
        this.ctx.beginPath();
        this.ctx.arc(centerX - 2, centerY - 2, radius / 3, 0, Math.PI * 2);
        this.ctx.fill();
    }

    drawSnake() {
        const body = this.snake.getBody();

        // 绘制蛇身
        for (let i = body.length - 1; i >= 1; i--) {
            const segment = body[i];
            this.ctx.fillStyle = CONFIG.COLORS.SNAKE_BODY;
            this.ctx.fillRect(
                segment.x * CONFIG.GRID_SIZE + 1,
                segment.y * CONFIG.GRID_SIZE + 1,
                CONFIG.GRID_SIZE - 2,
                CONFIG.GRID_SIZE - 2
            );
        }

        // 绘制蛇头
        const head = body[0];
        this.ctx.fillStyle = CONFIG.COLORS.SNAKE_HEAD;
        this.ctx.fillRect(
